import{_ as t,c as i,a1 as s,o as n}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Session Hijacking","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/10-session-hijacking/0-Introduction.md","filePath":"categories/ethical-hacking-labs/10-session-hijacking/0-Introduction.md"}'),o={name:"categories/ethical-hacking-labs/10-session-hijacking/0-Introduction.md"};function a(c,e,r,h,l,d){return n(),i("div",null,e[0]||(e[0]=[s('<h1 id="session-hijacking" tabindex="-1">Session Hijacking <a class="header-anchor" href="#session-hijacking" aria-label="Permalink to &quot;Session Hijacking&quot;">​</a></h1><p>The Session Hijacking attack consists of the exploitation of the web session control mechanism, which is normally managed for a session token.</p><p align="center"><img width="50%" src="https://www.greycampus.com/ckeditor_assets/pictures/231/content_ses.hij.intro.bmp"></p><p>Because http communication uses many different TCP connections, the web server needs a method to recognize every user’s connections. The most useful method depends on a token that the Web Server sends to the client browser after a successful client authentication. A session token is normally composed of a string of variable width and it could be used in different ways, like in the URL, in the header of the http requisition as a cookie, in other parts of the header of the http request, or yet in the body of the http requisition.</p><p>The Session Hijacking attack compromises the session token by stealing or predicting a valid session token to gain unauthorized access to the Web Server.</p><p>The session token could be compromised in different ways; the most common are:</p><ul><li>Predictable session token</li><li>Session Sniffing</li><li>Client-side attacks (XSS, malicious JavaScript Codes, Trojans, etc)</li><li>Man-in-the-middle attack</li><li>Man-in-the-browser attack</li></ul><p>Source: <a href="https://owasp.org/www-community/attacks/Session_hijacking_attack" target="_blank" rel="noreferrer">https://owasp.org/www-community/attacks/Session_hijacking_attack</a></p>',8)]))}const k=t(o,[["render",a]]);export{m as __pageData,k as default};
